class Solution:
    def popcountDepth(self, n, k):
        def depth(x):
            d = 0
            while x != 1:
                x = bin(x).count('1')
                d += 1
            return d
        if k == 0:
            return 1 if n >= 1 else 0
        bits = bin(n)[2:]
        L = len(bits)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(pos, ones, tight):
            if pos == L:
                return 1 if ones >= 1 and depth(ones) == k - 1 else 0
            hi = int(bits[pos]) if tight else 1
            total = 0
            for b in range(0, hi + 1):
                total += dp(pos + 1, ones + b, tight and b == hi)
            return total
        res = dp(0, 0, True)
        dp.cache_clear()
        if k == 1:
            res -= 1
        return res

