class Solution:
    def popcountDepth(self, n, k):
        import math
        dep = [0] * 64
        dep[1] = 0
        for x in range(2, 64):
            dep[x] = 1 + dep[bin(x).count('1')]
        def count_popcount(N, c):
            if c == 0:
                return 0
            bits = bin(N)[2:]
            L = len(bits)
            total = 0
            ones_so_far = 0
            for i, ch in enumerate(bits):
                if ch == '1':
                    rem = L - i - 1
                    need = c - ones_so_far
                    if 0 <= need <= rem:
                        total += math.comb(rem, need)
                    ones_so_far += 1
            if ones_so_far == c:
                total += 1
            return total
        if k == 0:
            return 1 if n >= 1 else 0
        ans = 0
        for c in range(1, 64):
            if dep[c] == k - 1:
                ans += count_popcount(n, c)
        if k == 1:
            ans -= 1
        return ans

