var popcountDepth = function(n, k) {
    n = BigInt(n);
    const dep = new Array(64).fill(0);
    const pc = (x) => { let c = 0; while (x > 0) { c += x & 1; x >>= 1; } return c; };
    for (let x = 2; x < 64; x++) dep[x] = 1 + dep[pc(x)];
    const comb = (a, b) => {
        if (b < 0 || b > a) return 0n;
        b = Math.min(b, a - b);
        let r = 1n;
        for (let i = 0; i < b; i++) r = r * BigInt(a - i) / BigInt(i + 1);
        return r;
    };
    const countPopcount = (N, c) => {
        if (c === 0) return 0n;
        const bits = N.toString(2);
        const L = bits.length;
        let total = 0n, ones = 0;
        for (let i = 0; i < L; i++) {
            if (bits[i] === '1') {
                const rem = L - i - 1;
                const need = c - ones;
                total += comb(rem, need);
                ones++;
            }
        }
        if (ones === c) total += 1n;
        return total;
    };
    if (k === 0) return n >= 1n ? 1 : 0;
    let ans = 0n;
    for (let c = 1; c < 64; c++) {
        if (dep[c] === k - 1) ans += countPopcount(n, c);
    }
    if (k === 1) ans -= 1n;
    return Number(ans);
};
